#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int i=0;i<T;++i){
        double k1,k2,k3,v; scanf("%lf %lf %lf %lf", &k1,&k2,&k3,&v);
        double speed = k1*k2*k3*v;
        double time = 100.0 / speed;
        double rounded = floor(time*100.0 + 0.5) / 100.0;
        if(rounded < 9.58) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

