code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int t=0; t<T; ++t){
            StringTokenizer st = new StringTokenizer(br.readLine());
            double k1 = Double.parseDouble(st.nextToken());
            double k2 = Double.parseDouble(st.nextToken());
            double k3 = Double.parseDouble(st.nextToken());
            double v  = Double.parseDouble(st.nextToken());
            double speed = k1*k2*k3*v;
            double time = 100.0 / speed;
            double rounded = Math.floor(time*100.0 + 0.5) / 100.0;
            out.append(rounded < 9.58 ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

